            Vacancy(company_id=c1.id, title="DevOps Engineer", specialty="devops", level="middle", description="Kubernetes, CI/CD, Terraform, мониторинг. Гибридный график.", salary_from=180000, salary_to=300000),
            Vacancy(company_id=c1.id, title="QA Engineer", specialty="qa", level="junior", description="Ручное и автоматизированное тестирование, pytest, Selenium.", salary_from=80000, salary_to=150000),
            Vacancy(company_id=c2.id, title="Аналитик данных", specialty="analyst", level="middle", description="SQL, Python, Tableau, A/B тесты, метрики продукта.", salary_from=120000, salary_to=200000),
            Vacancy(company_id=c2.id, title="Junior Python Developer", specialty="developer", level="junior", description="Python, REST API, базовые алгоритмы. Менторство.", salary_from=60000, salary_to=100000),
