        TaskTemplate(title="SQL: количество заказов по месяцам",domain=TaskDomain.SQL,level=DifficultyLevel.JUNIOR,description="Напишите SQL-запрос, который подсчитывает количество заказов по месяцам. Таблица orders(id, product, created_at). Используйте DATE_TRUNC или EXTRACT и GROUP BY.",input_format="SQL",output_format="месяц, количество",reference_solution="# решение",visible_tests=[{"input":"example","expected":"Подсказка: используйте EXTRACT(MONTH FROM ...) и GROUP BY"}],hidden_tests=[{"input":"check","expected":"GROUP BY"}]),
