        TaskTemplate(title="Расчёт юнит-экономики",domain=TaskDomain.METRICS,level=DifficultyLevel.MIDDLE,description="Даны: стоимость привлечения клиента (CAC), средний чек (AOV), количество покупок в год (freq), маржинальность (margin). Вычислите LTV = AOV × freq × margin и ROI = (LTV - CAC) / CAC × 100%. Выведите LTV и ROI через пробел.",input_format="CAC AOV freq margin",output_format="LTV ROI%",visible_tests=[{"input":"1000 5000 4 0.3","expected":"6000.0 500.0"}],hidden_tests=[{"input":"500 2000 2 0.5","expected":"2000.0 300.0"}],reference_solution="cac,aov,freq,margin=map(float,input().split())\nltv=aov*freq*margin\nroi=(ltv-cac)/cac*100\nprint(ltv,roi)"),

